def report_result(id_list, reports, k):
    pairs = set()
    for r in reports:
        a, b = r.split()
        pairs.add((a, b))
    cnt = {}
    for a, b in pairs:
        cnt[b] = cnt.get(b, 0) + 1
    banned = {u for u, c in cnt.items() if c >= k}
    mails = {u: 0 for u in id_list}
    for a, b in pairs:
        if b in banned:
            mails[a] += 1
    return [mails[u] for u in id_list]

